module RefModule(
    input clk,
    input reset,
    input load,
    input clear,
    input [15:0] data,
    output reg [15:0] q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk, posedge reset or posedge dbg_halt) begin
		if (reset)
			q <= 0;
		else if (clear)
			q <= 0;
		else if (load)
			q <= data;
	end
endmodule
